// --- Constants ----------------------------------------------------------------
const PALETTE = ["#0D5C4A","#1B7A64","#2A9D87","#5BBFB0","#0A7B6F","#145C4F","#3DADA0","#07463A","#248F7A","#1A6657","#0E4D40","#337A6E"];
const MONTHS_SHORT = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const MONTHS_FULL  = ["January","February","March","April","May","June","July","August","September","October","November","December"];
const DAY_LABELS   = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];
const WDAY_NAMES   = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
const DOW_TO_DAY   = {1:"Mon",2:"Tue",3:"Wed",4:"Thu",5:"Fri"};
const DOW_OPTS     = [{v:0,l:"Sun"},{v:1,l:"Mon"},{v:2,l:"Tue"},{v:3,l:"Wed"},{v:4,l:"Thu"},{v:5,l:"Fri"},{v:6,l:"Sat"}];



// --- Pure helpers -------------------------------------------------------------
function isCallType(t)   { return !!t&&["call","split-call"].includes(t); }
function clinicLabel(type, dayName, clinicHours, physCustomHours, partialHours) {
  if(!isClinicType(type)) return shiftLabel(type);
  // Partial-hours override takes top priority — always use the adjusted open/close,
  // regardless of shift type (clinic-3pm, clinic-12pm, etc). The partial-hours window
  // is the actual scheduled window for this date; the frozen shift type is irrelevant.
  if(partialHours) {
    const openStr=partialHours.open?fmt12(partialHours.open):"7a";
    const closeStr=partialHours.close?fmt12(partialHours.close):"(adj)";
    // Use partial close if set; otherwise fall through to type default
    if(partialHours.close) return `Clinic ${openStr}-${closeStr}`;
    // Only partial open set — show open, keep type-specific close
    if(type==="clinic-12pm") return `Clinic ${openStr}-12p`;
    if(type==="clinic-3pm")  return `Clinic ${openStr}-3:30p`;
    const dh=(physCustomHours&&dayName?physCustomHours[dayName]:null)||(clinicHours&&dayName?clinicHours[dayName]:null);
    return `Clinic ${openStr}-${dh?.close?fmt12(dh.close):"5p"}`;
  }
  // Physician's own custom hours take priority over practice-wide hours
  const dh=(physCustomHours&&dayName?physCustomHours[dayName]:null)
         ||(clinicHours&&dayName?clinicHours[dayName]:null);
  const openStr=dh?.open?fmt12(dh.open):"7a";
  if(type==="clinic-12pm") return `Clinic ${openStr}-12p`;
  if(type==="clinic-3pm")  return `Clinic ${openStr}-3:30p`;
  // standard clinic - use configured close time
  const closeStr=dh?.close?fmt12(dh.close):"5p";
  return `Clinic ${openStr}-${closeStr}`;
}
function isClinicType(t) { return !!t&&["clinic","clinic-3pm","clinic-12pm"].includes(t); }
function timeToHours(t24){
  if(!t24) return 0;
  const [h,m]=t24.split(":").map(Number);
  return h + m/60;
}
function clinicHoursForDay(dayName, clinicHours){
  // dayName: "Mon"..."Fri"
  const dh=clinicHours[dayName];
  if(!dh||!dh.open||!dh.close) return 10; // fallback
  return Math.round((timeToHours(dh.close)-timeToHours(dh.open))*2)/2; // round to 0.5h
}
function shiftHours(t, dayName, clinicHours, partialHours) {
  if(!t) return 0;
  if(t==="call") return 24;
  if(t==="split-call"||t==="cross-cover") return 12;
  if(isClinicType(t)&&partialHours?.open&&partialHours?.close) {
    // Use partial-hours window for this date
    return Math.max(0, Math.round((timeToHours(partialHours.close)-timeToHours(partialHours.open))*2)/2);
  }
  if(t==="clinic"&&dayName&&clinicHours) return clinicHoursForDay(dayName,clinicHours);
  if(t==="clinic") return 10;
  if(t==="clinic-3pm") return 8.5; // 7a-3:30p
  if(t==="clinic-12pm") return 5;
  if(t==="holiday"||t==="closure") return 0;
  return 0;
}
function shiftLabel(t) {
  return ({
    clinic:"Clinic",  "clinic-3pm":"Clinic ->3:30p","clinic-12pm":"Clinic ->12p",
    call:"On call (24h)","split-call":"Day call","cross-cover":"Night call",
    post:"Post-call off","wed-off":"Wed off",off:"Off",pto:"PTO",
    holiday:"Holiday","closure":"Clinic closed",
  })[t]||t||"-";
}
function dk(d) {
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
}
function addD(d,n){ const r=new Date(d); r.setDate(r.getDate()+n); return r; }
function startOfWeek(d){ const r=new Date(d); const dow=r.getDay(); r.setDate(r.getDate()-(dow===0?6:dow-1)); return r; }
function getDaysInMonth(y,m){ const days=[],d=new Date(y,m,1); while(d.getMonth()===m){days.push(new Date(d));d.setDate(d.getDate()+1);} return days; }
function getMonthList(n=6){ const t=new Date(),list=[]; for(let i=0;i<=n;i++){const d=new Date(t.getFullYear(),t.getMonth()+i,1);list.push({year:d.getFullYear(),month:d.getMonth()});} return list; }
function fmt12(t24){ if(!t24)return""; const [h,m]=t24.split(":").map(Number); return `${h%12||12}${m?":"+String(m).padStart(2,"0"):""}${h>=12?"p":"a"}`; }
function formatTs(ts){ if(!ts)return"Never"; const d=new Date(ts); return d.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})+" "+d.toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit",hour12:true}); }
function buildDateMap(list){ const map={}; list.forEach(p=>{ const s=new Date(p.start+"T00:00:00"),e=new Date(p.end+"T00:00:00"); for(let d=new Date(s);d<=e;d.setDate(d.getDate()+1)){const k=dk(new Date(d));if(!map[k])map[k]=new Set();map[k].add(p.docId);} }); return map; }
function escCsv(v){ const s=String(v??""); return s.includes(",")||s.includes('"')||s.includes("\n")?`"${s.replace(/"/g,'""')}"`:s; }
function buildCsv(rows){ return rows.map(r=>r.map(escCsv).join(",")).join("\n"); }
function makeCsv(rows){ return rows.map(r=>r.map(escCsv).join(",")).join("\n"); }
function downloadCsv(rows,filename){
  const csv=makeCsv(rows);
  const blob=new Blob([csv],{type:"text/csv"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");
  a.href=url; a.download=filename; document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}

// --- Lock horizon helpers -----------------------------------------------------
// Returns the 1st of the month that is `months` full months ahead of today.
// e.g. today = Apr 25, months = 2 → Jun 1 (Apr + 2 = Jun).
// "Full months" means we always land on a month boundary — no partial months.
function computeLockHorizon(today, months=2) {
  const d = new Date(today.getFullYear(), today.getMonth() + months, 1);
  return d;
}

// Human-readable label, e.g. "Jun 2026"
function lockHorizonLabel(today, months=2) {
  const d = computeLockHorizon(today, months);
  return `${MONTHS_SHORT[d.getMonth()]} ${d.getFullYear()}`;
}

// Is a given date string (YYYY-MM-DD) within the locked zone?
function isLocked(dateKey, lockDate) {
  return new Date(dateKey + "T00:00:00") < lockDate;
}

// --- Scheduler ----------------------------------------------------------------
function buildFullSchedule(physicians, crossCoverage, ptoMap, noCallMap, closedDays, clinicHours,
                           lockedSched={}, lockDate=null, permNoCallMap={}) {
  const callPool = physicians.filter(p=>p.inCallPool);
  const sched    = {};

  // -- Seed locked zone from existing schedule --
  // Any date before lockDate is pre-committed. We copy it into sched verbatim so
  // the equity counters (call counts, weekend spacing) read it correctly when
  // choosing assignments for the open zone. The main loop will skip these dates.
  if(lockDate) {
    Object.entries(lockedSched).forEach(([k,day])=>{
      if(new Date(k+"T00:00:00")<lockDate) {
        sched[k]={};
        Object.entries(day).forEach(([id,t])=>{ sched[k][parseInt(id)]=t; });
      }
    });
  }

  // -- Primitives --
  const gs  = (d,id)   => sched[dk(d)]?.[id];
  const fs  = (d,id,t) => { const k=dk(d); if(!sched[k])sched[k]={}; sched[k][id]=t; };
  const ise = (d,id,t) => { const k=dk(d); if(!sched[k])sched[k]={}; if(sched[k][id]===undefined)sched[k][id]=t; };
  const isPTO    = (d,id) => !!(ptoMap[dk(d)]?.has(id));
  const isNoCall = (d,id) => !!(noCallMap[dk(d)]?.has(id)) || !!(permNoCallMap[dk(d)]?.has(id));
  const isClosed = (d)    => !!closedDays[dk(d)];
  const isWeekend= (d)    => d.getDay()===0||d.getDay()===6;

  // -- Call counting --
  const totalCallCount = (id) =>
    Object.values(sched).reduce((c,day)=>c+(isCallType(day[id])?1:0),0);

  // 24h calls already assigned for this physician in this Mon-Sun week
  function fullCallsThisWeek(id, weekMon) {
    let c=0;
    for(let di=0;di<7;di++) if(gs(addD(weekMon,di),id)==="call") c++;
    return c;
  }

  // ISO week number
  function isoWeek(d) {
    const t=new Date(d); t.setHours(0,0,0,0);
    t.setDate(t.getDate()+3-(t.getDay()+6)%7);
    const w=new Date(t.getFullYear(),0,4);
    return 1+Math.round(((t-w)/86400000-3+(w.getDay()+6)%7)/7);
  }

  // Last Friday date (as Date obj) on which this physician started weekend day call.
  // Tracks the Fri of the Fri-Sat-Sun block, so gap math is in calendar weeks.
  function lastWeekendFriday(id) {
    let latest=null;
    for(const [k,day] of Object.entries(sched)){
      if(day[id]==="split-call"){
        const d=new Date(k+"T00:00:00");
        if(d.getDay()===5){ // Friday = start of weekend block
          if(latest===null||d>latest) latest=d;
        }
      }
    }
    return latest; // Date or null
  }

  // Weeks elapsed since a physician last took weekend call (null → never → treat as very large)
  function weeksSinceLastWeekend(id, fridayDate) {
    const last=lastWeekendFriday(id);
    if(last===null) return 9999;
    return Math.round((fridayDate-last)/(7*24*3600*1000));
  }

  // ISO week — kept for back-compat with weekday logic
  function isoWeek(d) {
    const t=new Date(d); t.setHours(0,0,0,0);
    t.setDate(t.getDate()+3-(t.getDay()+6)%7);
    const w=new Date(t.getFullYear(),0,4);
    return 1+Math.round(((t-w)/86400000-3+(w.getDay()+6)%7)/7);
  }

  // Weekend split-call count (number of weekend blocks assigned, not individual days)
  function wkendSplitCount(id) {
    let c=0;
    for(const [k,day] of Object.entries(sched)){
      if(day[id]==="split-call"&&new Date(k+"T00:00:00").getDay()===5) c++;
    }
    return c;
  }

  // -- Pick weekend day call doc (covers Fri+Sat+Sun) --
  // Enforces spacing of ~poolSize weeks between assignments for the same physician.
  // Sort priority: (1) longest wait since last weekend call, (2) fewest weekend blocks,
  // (3) fewest total call shifts. Hard minimum gap: 2 weeks always enforced.
  function pickWeekendCall(excl=new Set(), fridayDate=null, currentWeek=0) {
    const thuDate=fridayDate?addD(fridayDate,-1):null;
    const poolSize=Math.max(callPool.length,1);
    // Target gap: pool size weeks. Hard floor: 2 weeks.
    const targetGap=poolSize;
    const hardMin=2;

    const satDate=fridayDate?addD(fridayDate,1):null;
    const sunDate=fridayDate?addD(fridayDate,2):null;

    const base=callPool.filter(d=>{
      if(excl.has(d.id)) return false;
      // Block if PTO or no-call on ANY of the three weekend days (Fri, Sat, Sun)
      if(fridayDate&&(isPTO(fridayDate,d.id)||isNoCall(fridayDate,d.id))) return false;
      if(satDate&&(isPTO(satDate,d.id)||isNoCall(satDate,d.id))) return false;
      if(sunDate&&(isPTO(sunDate,d.id)||isNoCall(sunDate,d.id))) return false;
      if(thuDate&&gs(thuDate,d.id)==="call") return false;
      if(fridayDate){
        const weekMon=addD(fridayDate,-4);
        if(anyCallThisWeek(d.id,weekMon)) return false;
      }
      // Hard minimum gap — never repeat within 2 weeks
      if(fridayDate){
        const gap=weeksSinceLastWeekend(d.id,fridayDate);
        if(gap<hardMin) return false;
      }
      return true;
    });

    if(!base.length) return -1;

    // Preferred pool: docs who have waited at least targetGap weeks
    const pref=fridayDate
      ? base.filter(d=>weeksSinceLastWeekend(d.id,fridayDate)>=targetGap)
      : base;
    const pool=pref.length>0?pref:base;

    // Sort: longest wait first → fewest weekend blocks → fewest total calls
    pool.sort((a,b)=>{
      if(fridayDate){
        const waitDiff=weeksSinceLastWeekend(b.id,fridayDate)-weeksSinceLastWeekend(a.id,fridayDate);
        if(waitDiff!==0) return waitDiff;
      }
      const wDiff=wkendSplitCount(a.id)-wkendSplitCount(b.id);
      if(wDiff!==0) return wDiff;
      return totalCallCount(a.id)-totalCallCount(b.id);
    });

    // Return top pick — deterministic, no random tiebreak for spacing equity
    return pool[0].id;
  }

  // -- Pick weekday 24h call doc --
  function anyCallThisWeek(id, weekMon) {
    for(let di=0;di<7;di++){
      const t=gs(addD(weekMon,di),id);
      if(t==="call"||t==="split-call") return true;
    }
    return false;
  }

  // For 5-doc pool: doc who took last weekend's Fri-Sun day call is blocked
  // from weekday call Tue + Wed of the immediately following week.
  function blockedPostWeekend(id, forDay, weekMon) {
    if(callPool.length!==5) return false;
    const dow=forDay.getDay();
    if(dow!==2&&dow!==3) return false;
    const prevFri=addD(weekMon,-3);
    const prevSat=addD(weekMon,-2);
    const prevSun=addD(weekMon,-1);
    return (gs(prevFri,id)==="split-call"||gs(prevSat,id)==="split-call"||gs(prevSun,id)==="split-call");
  }

  function pickWeekdayCall(excl=new Set(), forDay=null, weekMon=null) {
    const el=callPool.filter(d=>{
      if(excl.has(d.id)) return false;
      if(forDay&&(gs(forDay,d.id)!==undefined||isPTO(forDay,d.id)||isNoCall(forDay,d.id))) return false;
      if(weekMon&&anyCallThisWeek(d.id,weekMon)) return false;
      if(forDay&&weekMon&&blockedPostWeekend(d.id,forDay,weekMon)) return false;
      return true;
    });
    if(!el.length) return -1;
    el.sort((a,b)=>totalCallCount(a.id)-totalCallCount(b.id));
    const minC=totalCallCount(el[0].id);
    const tied=el.filter(d=>totalCallCount(d.id)===minC);
    return tied[Math.floor(Math.random()*tied.length)].id;
  }

  // -- 3:30 return-from-post rule --
  // Only applies on weekdays when previous day was "post"
  function isReturnFromPost(d,id) {
    if(isWeekend(d)) return false;
    return gs(addD(d,-1),id)==="post";
  }
  function clinicShiftType(d,id) {
    return isReturnFromPost(d,id)?"clinic-3pm":"clinic";
  }

  // -- Fill a single day with clinic/pto/off for unassigned physicians --
  function fillClinic(day) {
    const dayName=DOW_TO_DAY[day.getDay()];
    physicians.forEach(p=>{
      if(gs(day,p.id)!==undefined) return;
      if(isPTO(day,p.id)) { fs(day,p.id,"pto"); return; }
      // Out-of-pool physician with custom hours: only work configured days
      if(!p.inCallPool && p.customHours) {
        const ch=p.customHours[dayName];
        if(!ch||!ch.enabled) { fs(day,p.id,"off"); return; }
        fs(day,p.id,"clinic"); return;
      }
      if(!p.inClinic) { fs(day,p.id,"off"); return; }
      fs(day,p.id,clinicShiftType(day,p.id));
    });
  }
  function fillHoliday(day) {
    physicians.forEach(p=>{ if(gs(day,p.id)===undefined) fs(day,p.id,"holiday"); });
  }

  // -- Main loop --
  const months   = getMonthList();
  const firstDay = new Date(months[0].year,months[0].month,1);
  const lastDay  = new Date(months[months.length-1].year,months[months.length-1].month+1,0);
  let wk         = addD(firstDay,-(firstDay.getDay()===0?6:firstDay.getDay()-1));

  // Coverage gaps — dates where no call physician could be assigned
  const coverageGaps = [];

  // -- Weekday call helper (defined before loop so it closes over coverageGaps) --
  function assignWeekdayCall(day, nextDay, weekMon) {
    const blk=new Set(physicians.filter(p=>
      gs(day,p.id)!==undefined||isPTO(day,p.id)||isNoCall(day,p.id)
    ).map(p=>p.id));
    const callDoc=pickWeekdayCall(blk,day,weekMon);
    if(callDoc>=0){
      fs(day,callDoc,"call");
      if(nextDay) ise(nextDay,callDoc,"post");
    } else {
      coverageGaps.push({date:dk(day), dow:day.getDay(), type:"weekday-24h"});
    }
    if(isClosed(day)) fillHoliday(day);
    else fillClinic(day);
    return callDoc;
  }

  while(wk<=lastDay) {
    const days=[]; for(let i=0;i<7;i++) days.push(addD(wk,i));
    const [mon,tue,wed,thu,fri,sat,sun]=days;
    const thisWeek=isoWeek(fri);
    const cpSize=callPool.length;
    // -- Lock zone: skip weeks that are entirely before the lock horizon --
    // Partially-overlapping weeks (straddle the boundary) are also skipped —
    // we never split a week. The equity counters still read the seeded locked data.
    if(lockDate && addD(wk,6) < lockDate) {
      wk=addD(wk,7);
      continue;
    }

    // -- 1. Cross-coverage night call (Dartmouth: Fri/Sat/Sun) --
    crossCoverage.filter(c=>c.active).forEach(cc=>{
      cc.coverDays.map(dow=>days.find(d=>d.getDay()===dow)).filter(Boolean)
        .forEach(day=>fs(day,cc.id,"cross-cover"));
    });

    // -- 2. Weekend day call: one physician covers Fri + Sat + Sun --
    const wkendDoc=pickWeekendCall(new Set(),fri,thisWeek);
    if(wkendDoc>=0){
      fs(fri,wkendDoc,"split-call");
      fs(sat,wkendDoc,"split-call");
      fs(sun,wkendDoc,"split-call");
      ise(addD(sun,1),wkendDoc,"post"); // Monday post-call
    } else {
      coverageGaps.push({date:dk(fri), dow:5, type:"weekend-day-call"});
    }

    // -- 3. Monday 24h call --
    const monCallDoc=assignWeekdayCall(mon,tue,mon);

    // -- 4. Tuesday 24h call --
    const tueCallDoc=assignWeekdayCall(tue,wed,mon);

    // -- 5. Wednesday: normal or 4-person split --
    // availForWeek: computed HERE — after Mon+Tue call assignments are written to sched,
    // so anyCallThisWeek() correctly sees who's already been assigned this week.
    // wedEligible = pool docs who could take a standalone Wed 24h shift:
    //   • not on PTO/no-call on Wed
    //   • not already on call Mon or Tue (anyCallThisWeek now accurate)
    //   • not the weekend doc (Fri-Sun committed)
    // Split fires when cpSize<=4 OR eligible pool collapses to <=1.
    const wedEligible=callPool.filter(d=>{
      if(isPTO(wed,d.id)||isNoCall(wed,d.id)) return false;
      if(anyCallThisWeek(d.id,mon)) return false;
      if(d.id===wkendDoc) return false;
      return true;
    }).length;
    const availForWeek = cpSize<=4 ? cpSize : wedEligible<=1 ? 4 : cpSize;

    // Rule (availForWeek<=4): split Wed into two 12h shifts — never leave it uncovered.
    //   Day call  7a-7p  → Mon call doc (was on-call Mon, post-call Tue, returns Wed 7a)
    //   Night call 7p-7a → Weekend doc (covering Fri-Sun day call this week)
    //
    // Availability check uses isPTO/isNoCall only — we intentionally ignore any "post"
    // written by ise() since those are soft and get overwritten by fs() here.
    //
    // Fallback chain so Wed is ALWAYS covered:
    //   1. Both anchors OK   → ideal split (split-call day + cross-cover night)
    //   2. Only day anchor   → Mon call doc takes full 24h call
    //   3. Only night anchor → Weekend doc takes full 24h call
    //   4. Neither           → equity picker via assignWeekdayCall
    if(availForWeek<=4){
      const wedDayAvail  = monCallDoc>=0 && !isPTO(wed,monCallDoc) && !isNoCall(wed,monCallDoc);
      const wedNightAvail= wkendDoc>=0   && !isPTO(wed,wkendDoc)   && !isNoCall(wed,wkendDoc);

      if(wedDayAvail && wedNightAvail){
        fs(wed,monCallDoc,"split-call");   // day 7a-7p
        fs(wed,wkendDoc,"cross-cover");    // night 7p-7a
        if(isClosed(wed)) fillHoliday(wed); else fillClinic(wed);
      } else if(wedDayAvail && !wedNightAvail){
        fs(wed,monCallDoc,"call");
        ise(thu,monCallDoc,"post");
        if(isClosed(wed)) fillHoliday(wed); else fillClinic(wed);
      } else if(!wedDayAvail && wedNightAvail){
        fs(wed,wkendDoc,"call");
        ise(thu,wkendDoc,"post");
        if(isClosed(wed)) fillHoliday(wed); else fillClinic(wed);
      } else {
        // Both anchors unavailable — equity picker guarantees coverage
        assignWeekdayCall(wed,thu,mon);
      }
    } else {
      assignWeekdayCall(wed,thu,mon);
    }

    // -- 6. Thursday 24h call --
    assignWeekdayCall(thu,fri,mon);

    // -- 7. Friday clinic fill (day call already set above) --
    if(isClosed(fri)) fillHoliday(fri); else fillClinic(fri);

    // -- 8. Sat/Sun fill --
    [sat,sun].forEach(day=>{
      const dayClosed=isClosed(day);
      physicians.forEach(p=>{
        if(gs(day,p.id)!==undefined) return;
        if(isPTO(day,p.id)) { fs(day,p.id,"pto"); return; }
        fs(day,p.id,dayClosed?"holiday":"off");
      });
    });

    wk=addD(wk,7);
  }

  // -- Gap-fill pass --
  // For any date that landed in coverageGaps with no call assigned, relax the
  // anyCallThisWeek constraint and assign the best-rested available physician.
  // Sort priority: (1) hard-deprioritize docs called within 2 days (minimum recovery),
  // (2) longest gap since last call (maximizes rest between shifts),
  // (3) fewest total call shifts (equity), (4) id (deterministic tiebreak).
  // PTO and noCall hard blocks are still respected.
  // NOTE: clinic-today heuristic intentionally removed — overwriting a clinic with 24h
  // call is disruptive regardless of who it hits; recency is the correct signal.

  // Helper: days elapsed since this physician last had any call-type shift,
  // looking only at dates strictly before `beforeDate`. Returns 9999 if never called
  // (never-called docs get highest scheduling priority in gap-fill).
  function daysSinceLastCall(id, beforeDate) {
    let latest = null;
    for(const [k, dayRow] of Object.entries(sched)) {
      const d = new Date(k + "T00:00:00");
      if(d >= beforeDate) continue;
      const t = dayRow[id];
      if(t==="call"||t==="split-call"||t==="cross-cover") {
        if(latest === null || d > latest) latest = d;
      }
    }
    if(latest === null) return 9999;
    return Math.round((beforeDate - latest) / (24*3600*1000));
  }

  coverageGaps.forEach(g => {
    const day = new Date(g.date + "T00:00:00");
    const daySlots = sched[g.date] || {};

    // Already covered by split logic or cross-cover — nothing to do
    if(Object.values(daySlots).some(t => t==="call"||t==="split-call"||t==="cross-cover")) return;

    // Relaxed pool: drop anyCallThisWeek, keep hard unavailability guards
    const relaxed = callPool.filter(d => {
      if(isPTO(day, d.id) || isNoCall(day, d.id)) return false;
      // Can't assign call on top of a hard shift (another call type or pto)
      const cur = daySlots[d.id];
      if(cur==="call"||cur==="split-call"||cur==="cross-cover"||cur==="pto") return false;
      return true;
    });

    if(!relaxed.length) return; // truly impossible — stays in gaps for the alert

    // Recency-aware sort — maximizes spacing, then equity, then determinism
    relaxed.sort((a, b) => {
      const aDays = daysSinceLastCall(a.id, day);
      const bDays = daysSinceLastCall(b.id, day);

      // 1. Hard-deprioritize anyone called within the last 2 days (minimum recovery window)
      const aRecent = aDays < 2 ? 1 : 0;
      const bRecent = bDays < 2 ? 1 : 0;
      if(aRecent !== bRecent) return aRecent - bRecent;

      // 2. Longest gap since last call wins — maximizes rest between calls
      if(bDays !== aDays) return bDays - aDays;

      // 3. Fewest total call shifts — maintains overall equity
      const callDiff = totalCallCount(a.id) - totalCallCount(b.id);
      if(callDiff !== 0) return callDiff;

      // 4. Deterministic tiebreak
      return a.id - b.id;
    });

    const filler = relaxed[0];
    fs(day, filler.id, "call");
    const nextDay = addD(day, 1);
    ise(nextDay, filler.id, "post");
  });

  // -- Post-loop safety sweep --
  // Ensure no physician has a clinic shift on a closed day (handles edge cases where
  // a holiday was added after the base assignments ran, or a call doc's post-call
  // lands on a closed day and the fill logic wrote clinic before closedDays was checked).
  Object.keys(sched).forEach(k=>{
    if(!closedDays[k]) return;
    const day=sched[k];
    Object.keys(day).forEach(idStr=>{
      const id=parseInt(idStr);
      const t=day[id];
      // Preserve call, split-call, cross-cover, post, pto — only replace clinic variants
      if(isClinicType(t)) day[id]="holiday";
    });
  });

  // Final gap validation: remove any date from coverageGaps that ended up
  // covered by the split-call logic or another fallback path.
  // A date is truly uncovered only if NO entity has call/split-call/cross-cover on it.
  const trueGaps = coverageGaps.filter(g => {
    const day = sched[g.date] || {};
    return !Object.values(day).some(t => t==="call" || t==="split-call" || t==="cross-cover");
  });

  return { sched, gaps: trueGaps };
}

function diffSchedules(oldS,newS,allEntities){
  const getName=id=>allEntities.find(e=>e.id===id)?.name||`#${id}`;
  const changes=[];
  const keys=new Set([...Object.keys(oldS||{}),...Object.keys(newS||{})]);
  keys.forEach(k=>{
    const o=oldS?.[k]||{},n=newS?.[k]||{};
    const ids=new Set([...Object.keys(o),...Object.keys(n)].map(Number));
    ids.forEach(id=>{if(o[id]!==n[id])changes.push({date:k,name:getName(id),from:o[id]||"-",to:n[id]||"-"});});
  });
  return changes.sort((a,b)=>a.date.localeCompare(b.date)||a.name.localeCompare(b.name));
}

