// --- Coverage Gap Alert -------------------------------------------------------
// Persistent modal — blocks until user acknowledges and takes action.
// Cannot be dismissed without clicking "I will resolve this".
function CallGapAlert({ gaps, onDismiss }) {
  const WDAY = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  const grouped = gaps.reduce((acc, g) => {
    const month = g.date.slice(0, 7);
    if(!acc[month]) acc[month] = [];
    acc[month].push(g);
    return acc;
  }, {});

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.7)",zIndex:8500,
      display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:"#FFF",borderRadius:12,maxWidth:560,width:"100%",
        boxShadow:"0 24px 80px rgba(0,0,0,.4)",display:"flex",flexDirection:"column",maxHeight:"85vh",overflow:"hidden"}}>

        {/* Header */}
        <div style={{background:"#7F1D1D",color:"#FFF",padding:"16px 22px",borderRadius:"12px 12px 0 0",flexShrink:0}}>
          <div style={{fontFamily:"Georgia,serif",fontWeight:700,fontSize:16,display:"flex",alignItems:"center",gap:10}}>
            <span style={{fontSize:20}}>🚨</span> URGENT — Call Coverage Gap Detected
          </div>
          <div style={{fontSize:11,color:"#FCA5A5",marginTop:4,fontFamily:"'DM Mono',monospace",letterSpacing:".06em"}}>
            REQUIRES IMMEDIATE ACTION · CANNOT BE DISMISSED WITHOUT ACKNOWLEDGEMENT
          </div>
        </div>

        {/* Body */}
        <div style={{padding:"18px 22px",overflowY:"auto",flex:1}}>
          <div style={{background:"#FEF2F2",border:"1px solid #FECACA",borderRadius:8,
            padding:"12px 16px",marginBottom:16,fontSize:13,color:"#7F1D1D",lineHeight:1.7}}>
            <strong>The schedule has {gaps.length} date{gaps.length!==1?"s":""} with no physician assigned to call.</strong>{" "}
            Every day of the year must have at least one physician on call. This is a non-negotiable coverage requirement.
            You must resolve these gaps before the schedule can be considered complete.
          </div>

          <div style={{fontWeight:700,fontSize:11,color:"#7F1D1D",fontFamily:"Georgia,serif",
            letterSpacing:".06em",marginBottom:10}}>UNCOVERED DATES ({gaps.length})</div>

          {Object.entries(grouped).map(([month,gs])=>(
            <div key={month} style={{marginBottom:12}}>
              <div style={{fontSize:11,color:"#991B1B",fontWeight:700,marginBottom:6,fontFamily:"'DM Mono',monospace"}}>
                {month}
              </div>
              {gs.map((g,i)=>(
                <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"6px 10px",
                  background:i%2===0?"#FEF2F2":"#FFF",borderRadius:5,marginBottom:2,
                  border:"1px solid #FECACA"}}>
                  <span style={{fontSize:18}}>⚠</span>
                  <div>
                    <span style={{fontWeight:700,fontSize:13,color:"#7F1D1D",fontFamily:"'DM Mono',monospace"}}>
                      {WDAY[g.dow]}, {g.date}
                    </span>
                    <span style={{fontSize:11,color:"#991B1B",marginLeft:8}}>
                      {g.type==="weekend-day-call"?"Weekend day call — no physician available":"24h weekday call — no physician available"}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          ))}

          <div style={{background:"#FFFBEB",border:"1px solid #FCD34D",borderRadius:8,
            padding:"10px 14px",fontSize:12,color:"#78350F",marginTop:8,lineHeight:1.6}}>
            <strong>To resolve:</strong> Go to <strong>Time Off</strong> to review PTO requests, check{" "}
            <strong>Roster</strong> to confirm call pool membership, or use <strong>Edit Mode</strong> to manually
            assign call on the affected dates. Then regenerate the schedule.
          </div>
        </div>

        {/* Footer — single button, no escape */}
        <div style={{padding:"14px 22px",borderTop:"1px solid #FECACA",flexShrink:0,
          background:"#FEF2F2",borderRadius:"0 0 12px 12px",display:"flex",justifyContent:"flex-end"}}>
          <button onClick={onDismiss}
            style={{background:"#991B1B",color:"#FFF",border:"none",borderRadius:7,
              padding:"10px 22px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'DM Sans',sans-serif"}}>
            I understand — I will resolve these gaps
          </button>
        </div>
      </div>
    </div>
  );
}

// --- PTO Conflict Warning -----------------------------------------------------
// Fires when a new PTO request would result in 2+ call-pool physicians off simultaneously.
// Must be acknowledged before the request is saved or cancelled.
function PtoConflictAlert({ conflictDates, onProceed, onCancel }) {
  const MONTHS_SHORT2 = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const formatDate = k => {
    const d = new Date(k+"T00:00:00");
    const days = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
    return `${days[d.getDay()]}, ${MONTHS_SHORT2[d.getMonth()]} ${d.getDate()}, ${d.getFullYear()}`;
  };
  const shown = conflictDates.slice(0, 10);

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.65)",zIndex:8400,
      display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:"#FFF",borderRadius:12,maxWidth:500,width:"100%",
        boxShadow:"0 24px 80px rgba(0,0,0,.35)",display:"flex",flexDirection:"column",maxHeight:"80vh",overflow:"hidden"}}>

        <div style={{background:"#78350F",color:"#FFF",padding:"14px 20px",borderRadius:"12px 12px 0 0",flexShrink:0}}>
          <div style={{fontFamily:"Georgia,serif",fontWeight:700,fontSize:15,display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:18}}>⚠</span> PTO Overlap Warning — Call Coverage at Risk
          </div>
          <div style={{fontSize:11,color:"#FDE68A",marginTop:3,fontFamily:"'DM Mono',monospace",letterSpacing:".06em"}}>
            ACKNOWLEDGEMENT REQUIRED BEFORE PROCEEDING
          </div>
        </div>

        <div style={{padding:"16px 20px",overflowY:"auto",flex:1}}>
          <p style={{fontSize:13,color:"#78350F",lineHeight:1.7,marginTop:0,
            background:"#FFFBEB",border:"1px solid #FCD34D",borderRadius:7,padding:"10px 14px"}}>
            This PTO request overlaps with another call-pool physician's time off on <strong>{conflictDates.length} date{conflictDates.length!==1?"s":""}</strong>.
            With multiple call-pool physicians unavailable simultaneously, the equity engine may not be able to
            fill all call shifts. <strong>Call coverage gaps are a serious scheduling risk.</strong>
          </p>

          <div style={{fontWeight:700,fontSize:11,color:"#92400E",fontFamily:"Georgia,serif",
            letterSpacing:".06em",marginBottom:8}}>OVERLAP DATES</div>
          <div style={{display:"flex",flexDirection:"column",gap:3,marginBottom:12}}>
            {shown.map((k,i)=>(
              <div key={k} style={{fontSize:12,padding:"5px 10px",borderRadius:5,
                background:i%2===0?"#FFFBEB":"#FFF",border:"1px solid #FCD34D",
                color:"#78350F",fontFamily:"'DM Mono',monospace"}}>
                {formatDate(k)}
              </div>
            ))}
            {conflictDates.length>10&&(
              <div style={{fontSize:11,color:"#92400E",padding:"4px 10px"}}>
                ...and {conflictDates.length-10} more dates.
              </div>
            )}
          </div>
          <div style={{fontSize:12,color:"#6B7280",lineHeight:1.6}}>
            You may proceed and save this request, or cancel and adjust the dates.
            If you proceed, regenerate the schedule and check for coverage alerts.
          </div>
        </div>

        <div style={{padding:"12px 20px",borderTop:"1px solid #FCD34D",flexShrink:0,
          background:"#FFFBEB",borderRadius:"0 0 12px 12px",display:"flex",gap:10,justifyContent:"flex-end"}}>
          <button onClick={onCancel}
            style={{background:"#FFF",color:"#78350F",border:"1px solid #FCD34D",borderRadius:7,
              padding:"8px 18px",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"'DM Sans',sans-serif"}}>
            Cancel — revise dates
          </button>
          <button onClick={onProceed}
            style={{background:"#92400E",color:"#FFF",border:"none",borderRadius:7,
              padding:"8px 18px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'DM Sans',sans-serif"}}>
            I understand — save anyway
          </button>
        </div>
      </div>
    </div>
  );
}

